section "tome-orcs/data/birth/races/whitehooves.lua"

t("Skin", "Peau", "birth facial category")
t("Facial features", "Traits du visage", "birth facial category")
t("Horns", "Cornes", "birth facial category")
t("Special", "Spécial", "birth facial category")
t("Undead", "Mort-vivant", "_t")
t("Grave strength, dread will, this flesh cannot stay still. Kings die, masters fall, we will outlast them all.", "Force sépulcrale, volonté de terreur, cette chair ne connaît point la torpeur. Les rois périssent, les maîtres s'effondrent, nous leur survivrons tous, dans l'ombre.", "_t")
t("Undead are humanoids (Humans, Elves, Dwarves, ...) that have been brought back to life by the corruption of dark magics.", "Les morts-vivants sont des humanoïdes (Humains, Elfes, Nains...) ramenés à la vie par la corruption des magies noires.", "_t")
t("Undead can take many forms, from ghouls to vampires and liches.", "Les morts-vivants peuvent prendre de nombreuses formes, des goules aux vampires en passant par les liches.", "_t")
t("Skin Color 1", "Couleur de peau 01", "_t")
t("Skin Color 2", "Couleur de peau 02", "_t")
t("Skin Color 3", "Couleur de peau 03", "_t")
t("Skin Color 4", "Couleur de peau 04", "_t")
t("Skin Color 5", "Couleur de peau 05", "_t")
t("Skin Color 6", "Couleur de peau 06", "_t")
t("Skin Color 7", "Couleur de peau 07", "_t")
t("Demonic Red Skin", "Peau Rouge Démoniaque", "_t")
t("Beard 1", "Barbe 01", "_t")
t("Beard 2", "Barbe 02", "_t")
t("Redhead Beard", "Barbe Rousse", "_t")
t("Hair 1", "Cheveux 01", "_t")
t("Hair 2", "Cheveux 02", "_t")
t("Hair 3", "Cheveux 03", "_t")
t("Hair 4", "Cheveux 04", "_t")
t("Redhead Hair 1", "Cheveux Roux 01", "_t")
t("Redhead Hair 2", "Cheveux Roux 02", "_t")
