[[#{bold}#
Inilasac Salocin
#{normal}#32 - 120#{italic}#
Tous les grimoires se souviendront de toi
Et de tes sombres bénédictions
#{normal}#]],
"_t")

t([[#{bold}#
RIP Cecil Farion
#{normal}#98 - 122#{italic}#
Noble in mind
Pure in spirit
Rest now from the burdens of the flesh

#{normal}#A fresh rose lies here]],
[[#{bold}#
RIP Cecil Farion
#{normal}#98 - 122#{italic}#
Noble d’esprit
Pur de cœur
Repose maintenant des fardeaux de la chair

#{normal}#Une rose fraîche repose ici]],"_t")

