section "mod-tome/data/quests/brotherhood-of-alchemists.lua"

t("The Brotherhood of Alchemists", "La Confrérie des Alchimistes", "_t")
t("#LIGHT_GREEN#Thanks to your timely aid, %s is the newest member of the Brotherhood of Alchemists.#WHITE#", "#LIGHT_GREEN#Grâce à votre aide opportune, %s est le tout nouveau membre de la Confrérie des Alchimistes.#WHITE#", "tformat")
t("#RED#You aided various denizens of Maj'Eyal in their attempts to join the Brotherhood of Alchemists, though you did not prove the deciding factor for any. This year's new member is %s.#WHITE#", "#RED#Vous avez aidé divers habitants de Maj'Eyal dans leurs tentatives de rejoindre la Confrérie des Alchimistes, bien que vous n'ayez été le facteur décisif pour aucun d'entre eux. Le nouveau membre de cette année est %s.#WHITE#", "tformat")
t("#LIGHT_BLUE#Various alchemists around Maj'Eyal are competing to gain entry into the great Brotherhood of Alchemists, and one or more have enlisted your aid.#WHITE#", "#LIGHT_BLUE#Divers alchimistes à travers Maj'Eyal sont en compétition pour intégrer la grande Confrérie des Alchimistes, et un ou plusieurs ont sollicité votre aide.#WHITE#", "_t")
t("#GREEN#You have aided %s in creating an %s.#WHITE#", "#GREEN#Vous avez aidé %s à créer un(e) %s.#WHITE#", "tformat")
t("#RED#%s has completed an %s without your aid.#WHITE#", "#RED#%s a terminé un(e) %s sans votre aide.#WHITE#", "tformat")
t("#SLATE#Having failed to gain admittance to the Brotherhood of the Alchemists, %s no longer needs your help making the %s.", "#SLATE#Ayant échoué à intégrer la Confrérie des Alchimistes, %s n'a plus besoin de votre aide pour fabriquer le/la %s.", "tformat")
t("%s needs your help making an %s. He has given you some notes on the ingredients:", "%s a besoin de votre aide pour fabriquer un(e) %s. Il vous a donné quelques notes sur les ingrédients :", "tformat")
t("#SLATE#  * 'Needed: one %s. %s'#WHITE#", "#SLATE#  * 'Requis : un(e) %s. %s'#WHITE#", "tformat")
t("#LIGHT_GREEN#  * You've found the needed %s.#WHITE#", "#LIGHT_GREEN#  * Vous avez trouvé le/la %s requis(e).#WHITE#", "tformat")
t("#CRIMSON#Your timetravel has no effect on pre-determined outcomes such as this.", "#CRIMSON#Votre voyage temporel n'a aucun effet sur les résultats prédéterminés comme celui-ci.", "_t")
t("#VIOLET#You can check the ingredients you possess by pressing Escape and selecting 'Show ingredients'.", "#VIOLET#Vous pouvez vérifier les ingrédients en votre possession en appuyant sur Échap et en sélectionnant « Afficher les ingrédients ».", "log")
t("You receive: %s", "Vous recevez : %s", "logPlayer")
t("elixir of the fox", "élixir du renard", "_t")
t("elixir of avoidance", "élixir d'esquive", "_t")
t("elixir of precision", "élixir de précision", "_t")
t("elixir of mysticism", "élixir de mysticisme", "_t")
t("elixir of the savior", "élixir du sauveur", "_t")
t("elixir of mastery", "élixir de maîtrise", "_t")
t("elixir of explosive force", "élixir de force explosive", "_t")
t("elixir of serendipity", "élixir de sérendipité", "_t")
t("elixir of focus", "élixir de concentration", "_t")
t("elixir of brawn", "élixir de muscles", "_t")
