section "mod-tome/data/quests/strange-new-world.lua"

t("Strange new world", "Un monde nouveau et étrange", "_t")
t("You arrived through the farportal in a cave, probably in the Far East.", "Vous êtes arrivé dans une grotte via un téléporteur lointain, probablement en Extrême-Orient.", "_t")
t("Upon arrival you met an Elf and an orc fighting.", "À votre arrivée, vous avez trouvé un Elfe et un orque en plein combat.", "_t")
t("You decided to side with the Elven lady.", "Vous avez décidé de prendre le parti de l'Elfe.", "_t")
t("You decided to side with the orc.", "Vous avez décidé de prendre le parti de l'orque.", "_t")
t("Fillarel told you to go to the southeast and meet with High Sun Paladin Aeryn.", "Fillarel vous a dit d'aller au sud-est pour rencontrer la Haute Paladine du Soleil Aeryn.", "_t")
t("Krogar told you to go to the west and look for the Kruk Pride.", "Krogar vous a dit d'aller à l'ouest chercher la Fierté de Kruk.", "_t")
t("%s go to the west, and find Kruk Pride!", "%s, allez vers l'ouest et trouvez la Fierté de Kruk !", "tformat")
t("%s go to the southeast, and tell Aeryn what happened to me!", "%s, allez vers le sud-est et racontez à Aeryn ce qui m'est arrivé !", "tformat")

