t("orb", "orbe", "entity name")
t("Strange Orb", "Orbe étrange", "_t")
t("The orb looks inactive.", "L'orbe semble inactif.", "_t")
t("The orb seems to drip water.", "L'orbe semble suinter.", "_t")
t("The orb is covered in dust.", "L'orbe est couvert de poussière.", "_t")
t("The orb is floating in the air.", "L'orbe flotte dans les airs.", "_t")
t("Small seeds seem to be growing inside the orb.", "Des graines poussent dans l'orbe.", "_t")
t("The orb swirls with magical energies.", "L'orbe tourbillonne d'énergies magiques.", "_t")
t("Flames burst out of the orb.", "Des flammes jaillissent de l'orbe.", "_t")
t("The orb seems to absorb all light.", "L'orbe semble absorber la lumière.", "_t")
t("The orb is drips with thick blood.", "L'orbe suinte de sang épais.", "_t")
t("The orb is icy to the touch.", "L'orbe est glacé.", "_t")
t("Time seems to slow down around the orb.", "Le temps ralentit autour de l'orbe.", "_t")
t("Your mind is filled with strange thoughts as you approach the orb.", "Votre esprit est rempli de pensées bizarres en approchant de l'orbe.", "_t")
t("The orb seems to corrupt all it touches.", "L'orbe semble corrompre tout ce qu'il touche.", "_t")
