section "mod-tome/data/zones/sandworm-lair/objects.lua"

t("Song of the Sands", "Chanson des Sables", "entity name")
t("Some people get the weirdest ideas!", "Certains ont des idées bien étranges !", "_t")
t("corpse", "cadavre", "entity type")
t("heart", "cœur", "entity subtype")
t("Heart of the Sandworm Queen", "Cœur de la Reine des vers des sables", "entity name")
t("pulsing organ", "organe pulsant", "_t")
t([[The heart of the Sandworm Queen, ripped from her dead body.
You could ... consume it, should you feel mad enough or you could try to corrupt it somewhere.]], "Le cœur de la Reine, arraché de son corps. Vous pourriez... le manger, si vous êtes assez fou.", "_t")
t("consume the heart", "manger le cœur", "_t")
t("#00FFFF#You consume the heart and feel the knowledge of this very old creature fill you!", "#00FFFF#Vous mangez le cœur et sentez le savoir de cette créature ancestrale vous envahir !", "logPlayer")
t("You have %d stat point(s) to spend. Press p to use them.", "Vous avez %d point(s) de statistiques. Appuyez sur 'p'.", "logPlayer")
t("You have %d class talent point(s) to spend. Press p to use them.", "Vous avez %d point(s) de talent de classe. Appuyez sur 'p'.", "logPlayer")
t("You have %d generic talent point(s) to spend. Press p to use them.", "Vous avez %d point(s) de talent générique. Appuyez sur 'p'.", "logPlayer")
t("You are transformed by the heart of the Queen!", "Vous êtes transformé par le cœur de la Reine !", "logPlayer")
t("#00FF00#You gain an affinity for nature. You can now learn new Harmony talents (press p).", "#00FF00#Vous gagnez une affinité avec la nature. Apprenez de nouveaux talents d'Harmonie (p).", "logPlayer")
t("blood", "sang", "entity subtype")
t("Wyrm Bile", "Bile de Wyrm", "entity name")
t("putrescent potion", "potion putrescente", "_t")
t("A vial of thick, lumpy fluid. Who knows what this will do to you if you drink it?", "Une fiole de liquide épais et grumeleux. Qui sait ce que ça va vous faire ? Probablement rien de bon.", "_t")
t("drink the vile fluid", "boire ce fluide infect", "_t")
t("#CRIMSON#Your timetravel has no effect on pre-determined outcomes such as this.", "#CRIMSON#Vos voyages dans le temps n'ont aucun effet sur des résultats aussi prévisibles.", "_t")
t("#00FFFF#You drink the wyrm bile and feel forever transformed!", "#00FFFF#Vous buvez la bile et vous sentez transformé pour toujours !", "logPlayer")
t("You have %d category point(s) to spend. Press p to use them.", "Vous avez %d point(s) de catégorie. Appuyez sur 'P' pour les utiliser.", "log")
t("#00FF00#Your stats have changed! (Str %s, Dex %s, Mag %s, Wil %s, Cun %s, Con %s)", "#00FF00#Vos statistiques ont changé ! (For %s, Dex %s, Mag %s, Vol %s, Rus %s, Con %s)", "logPlayer")
t("red", "rouge", "entity subtype")
t("Atamathon's Lost Ruby Eye", "Œil de rubis perdu d'Atamathon", "entity name")
t([[One of the ruby eyes of the legendary giant golem Atamathon.
It is said it was made by the halflings during the Age of Pyre as a weapon against the orcs. Even though it was destroyed it managed to deal a crippling blow by killing their leader, Garkul the Devourer.]], [[Un des yeux du légendaire golem Atamathon. Fabriqué par les halfelins pour contrer les orcs. Il a réussi à tuer Garkul avant d'être détruit. Un joli jouet.], "_t")

