section "mod-tome/data/zones/shertul-fortress/grids.lua"

t("%0.2f Energy Stored", "%0.2f d'énergie stockée", "tformat")
t("stair back to the lake of Nur", "escalier vers le lac de Nur", "entity name")
t("teleportation circle to the surface", "cercle de téléportation vers la surface", "entity name")
t("teleportation circle for Melinda", "cercle de téléportation pour Melinda", "entity name")
t("Sher'Tul Control Orb", "Orbe de contrôle Sher'Tul", "entity name")
t("Exploratory Farportal", "Farportal d'exploration", "entity name")
t([[A farportal is a way to travel incredible distances in the blink of an eye. They were left behind by the powerful Sher'tul race.
This farportal is not connected to any other portal. It is made for exploration; you cannot know where it will send you.
It should automatically create a portal back, but it might not be near your arrival zone.]], "Un farportal permet de voyager très loin en un clin d'œil. Héritage des Sher'tul. Celui-ci n'est pas connecté, donc c'est pour l'exploration, et vous ne savez pas où vous allez. Il devrait créer un portail de retour, mais ne comptez pas trop dessus.", "_t")
t("#VIOLET#You enter the swirling portal and in the blink of an eye you set foot in a strangely familiar zone, right next to a farportal...", "#VIOLET#Vous entrez dans le portail et, en un clin d'œil, vous vous retrouvez dans une zone étrangement familière, juste à côté d'un farportal...", "log")
t("#VIOLET#You enter the swirling portal and in the blink of an eye you set foot in strange empty space...", "#VIOLET#Vous entrez dans le portail et vous vous retrouvez dans un espace vide et étrange...", "log")
t("Exploratory Farportal", "Farportal d'exploration", "_t")
t("The farportal seems to be inactive", "Le farportal semble inactif", "_t")
t("The farportal is broken and will not be usable anymore.", "Le farportal est cassé, inutile d'insister.", "_t")
t("The fortress does not have enough energy to power a trip through the portal.", "La forteresse n'a pas assez d'énergie. Payez vos factures, voyons.", "_t")
t("Do you want to travel in the farportal? You cannot know where you will end up.", "Vous voulez vraiment tenter le coup ? Vous n'avez aucune idée d'où vous allez atterrir.", "_t")
t("Exploratory Farportal exit", "Sortie de Farportal d'exploration", "_t")
t("#VIOLET#As %s falls you notice a portal appearing.", "#VIOLET#Alors que %s tombe, vous voyez un portail apparaître.", "logSeen")
t("#VIOLET#Your rod of recall shakes, a portal appears beneath you.", "#VIOLET#Votre baguette de rappel tremble, un portail apparaît sous vos pieds.", "logSeen")
t("#VIOLET#You enter the swirling portal and in the blink of an eye you set foot in an unfamiliar zone, with no trace of the portal...", "#VIOLET#Vous entrez dans le portail et, en un clin d'œil, vous arrivez dans une zone inconnue, sans aucune trace du portail...", "log")
t("Library of Lost Mysteries", "Bibliothèque des Mystères Perdus", "entity name")
t("Yiilkgur's Library of Lost Mysteries", "Bibliothèque des Mystères Perdus de Yiilkgur", "_t")
t("Receiving the lost knowledge of the universe...", "Réception du savoir perdu de l'univers en cours... Ça va être long.", "_t")
t("wall", "mur", "entity type")
t("floor", "sol", "entity subtype")
