section "mod-tome/mod/class/EscortRewards.lua"

t("Please help me! I am afraid I lost myself in this place. I know there is a recall portal left around here by a friend, but I have fought too many battles, and I fear I will not make it. Would you help me?", "Pitié, aidez-moi ! Je crains de m'être perdu dans ce trou à rats. Je sais qu'un ami a laissé un portail de rappel dans le coin, mais j'ai enchaîné trop de combats et je ne pense pas pouvoir tenir la distance. Vous m'aidez ?", "_t")
t("%s, the lost warrior", "%s, le guerrier perdu", "_t")
t("He looks tired and wounded.", "Il a l'air épuisé et mal en point.", "_t")
t("Please help me! I am afraid I lost myself in this place. I know there is a recall portal left around here by a friend, but I will not be able to continue the road alone. Would you help me?", "Pitié, aidez-moi ! Je crains de m'être perdue dans ce trou à rats. Je sais qu'un ami a laissé un portail de rappel dans le coin, mais je ne serai jamais capable de finir la route seule. Vous m'aidez ?", "_t")
t("%s, the injured seer", "%s, la voyante blessée", "_t")
t("She looks tired and wounded.", "Elle a l'air épuisée et mal en point.", "_t")
t("%s, the repented thief", "%s, le voleur repenti", "_t")
t("%s, the lone alchemist", "%s, l'alchimiste solitaire", "_t")
t("%s, the lost sun paladin", "%s, la paladine du soleil perdue", "_t")
t("%s, the lost defiler", "%s, la profanatrice perdue", "_t")
t("temporal portal", "portail temporel", "_t")
t([[Oh but you are ... are you ?! ME?!
		So I was right, this is not my original time-thread!
		Please help me! I am afraid I lost myself in this place. I know there is a temporal portal left around here by a friend, but I have fought too many battles, and I fear I will not make it. Would you help me? Would you help .. yourself?]], [[Oh mais attendez... vous êtes... MOI ?!
		J'avais donc raison, ce n'est pas ma trame temporelle d'origine !
		Aidez-moi, je vous en prie ! Je crains de m'être perdu dans ce trou à rats. Je sais qu'un ami a laissé un portail temporel dans le coin, mais j'ai enchaîné trop de combats pour y arriver. Vous m'aidez ? Vous aideriez... une autre version de vous-même ?]], "_t")
t("%s, temporal explorer", "%s, l'exploratrice temporelle", "_t")
t("She looks tired and wounded. She is so similar to you and yet completely different. Weird.", "Elle a l'air épuisée et mal en point. Elle est si semblable à vous, et pourtant si différente. Étrange.", "_t")
t("%s, the worried loremaster", "%s, l'érudite inquiète", "_t")
t("spell", "sortilège", "save name")
t("physical", "physique", "save name")
t("Select the party member to receive the reward:", "Sélectionnez le membre du groupe qui recevra la récompense :", "_t")
t("improved %s by +%d", "a amélioré %s de +%d", "tformat")
t("[Improve %s by +%d]", "[Améliorer %s de +%d]", "tformat")
t("improved %s save by +%d", "a amélioré la sauvegarde (%s) de +%d", "tformat")
t("[Improve %s save by +%d]", "[Améliorer la sauvegarde (%s) de +%d]", "tformat")
