section "mod-tome/mod/dialogs/DeathDialog.lua"

t("You have #LIGHT_RED#died#LAST#!", "Vous êtes #LIGHT_RED#mort#LAST#!", "_t")
t([[Death in #{bold}#Tales of Maj'Eyal#{normal}# is usually permanent, but if you have a means of resurrection it will be proposed in the menu below.
You can dump your character data to a file to remember her/him forever, or you can exit and try once again to survive in the wilds!
]], [[La mort dans #{bold}#Tales of Maj'Eyal#{normal}# est généralement permanente, mais si vous disposez d'un moyen de résurrection, il sera proposé dans le menu ci-dessous.
Vous pouvez exporter les données de votre personnage vers un fichier pour vous souvenir de lui à jamais, ou quitter et tenter une nouvelle fois de survivre dans ces terres sauvages !
]], "_t")
t([[#LIGHT_GREEN#During your game you#WHITE#:
* %s]], [[#LIGHT_GREEN#Durant votre partie, vous#WHITE# :
* %s]], "tformat")
t("#LIGHT_RED#You have %d life(s) left.", "#LIGHT_RED#Il vous reste %d vie(s).", "tformat")
t("#LIGHT_RED#You have no more lives left.", "#LIGHT_RED#Vous n'avez plus de vies.", "tformat")
t("#LIGHT_RED#From the brink of death you seem to be yanked to another plane.", "#LIGHT_RED#Au bord de la mort, vous semblez être arraché vers un autre plan.", "log")
t("Message Log", "Journal des messages", "_t")
t("#LIGHT_BLUE#You resurrect! CHEATER!", "#LIGHT_BLUE#Vous ressuscitez ! TRICHEUR !", "logPlayer")
t("#LIGHT_RED#The Blood of Life rushes through your dead body. You come back to life!", "#LIGHT_RED#Le Sang de Vie parcourt votre cadavre. Vous revenez à la vie !", "logPlayer")
t("#YELLOW#Your bones magically knit back together. You are once more able to dish out pain to your foes!", "#YELLOW#Vos os se ressoudent par magie. Vous êtes de nouveau prêt à faire souffrir vos ennemis !", "logPlayer")
t("#YELLOW#Your %s is consumed and disappears! You come back to life!", "#YELLOW#Votre %s est consommé et disparaît ! Vous revenez à la vie !", "logPlayer")
t("You managed to die on the eidolon plane! DIE!", "Vous avez réussi à mourir sur le plan eidolon ! CRÈVE !", "logPlayer")
t("Resurrect by cheating", "Ressusciter en trichant", "_t")
t("Resurrect with the Blood of Life", "Ressusciter avec le Sang de Vie", "_t")
t("Re-assemble your bones and resurrect (Skeleton ability)", "Réassembler vos os pour ressusciter (capacité Squelette)", "_t")
t("Resurrect by consuming %s", "Ressusciter en consommant %s", "tformat")
t("Resurrect with Adventurer Mode (%d life(s) left)", "Ressusciter avec le mode Aventurier (%d vie(s) restante(s))", "tformat")
t("Resurrect with Exploration Mode", "Ressusciter avec le mode Exploration", "_t")
t("Message/Chat log (allows to talk)", "Journal des messages/chat (permet de parler)", "_t")
