t("generic", "générique", "_t")
t("Not enough %s talent points", "Pas assez de points de talent %s", "tformat")
t("You have no %s talent points left!", "Plus de points de talent %s disponibles !", "tformat")
t("Cannot learn talent", "Impossible d'apprendre le talent", "_t")
