t("%s is purged of diseases!", "%s est purgé de ses maladies !", "logSeen")
t("#DARK_GREEN#You feel nature's power protecting you!", "#DARK_GREEN#Vous sentez le pouvoir de la nature vous protéger !", "logPlayer")
t("Star Shot", "Tir Stellaire", "entity name")
